28: func (s *Validation) ValidateSignature(plugin *plugins.Plugin) error {
29: 	if plugin.Signature.IsValid() {
30: 		s.log.Debug("Plugin has valid signature", "id", plugin.ID)
31: 		return nil
32: 	}
33: 
34: 	// If a plugin is nested within another, create links to each other to inherit signature details
35: 	if plugin.Parent != nil {
36: 		if plugin.IsCorePlugin() || plugin.Signature.IsInternal() {
37: 			s.log.Debug("Not setting descendant plugin's signature to that of root since it's core or internal",
38: 				"plugin", plugin.ID, "signature", plugin.Signature, "isCore", plugin.IsCorePlugin())
39: 		} else {
40: 			s.log.Debug("Setting descendant plugin's signature to that of root", "plugin", plugin.ID,
41: 				"root", plugin.Parent.ID, "signature", plugin.Signature, "rootSignature", plugin.Parent.Signature)
42: 			plugin.Signature = plugin.Parent.Signature
43: 			plugin.SignatureType = plugin.Parent.SignatureType
44: 			plugin.SignatureOrg = plugin.Parent.SignatureOrg
45: 			if plugin.Signature.IsValid() {
46: 				s.log.Debug("Plugin has valid signature (inherited from root)", "id", plugin.ID)
47: 				return nil
48: 			}
49: 		}
50: 	}
51: 
52: 	if plugin.IsCorePlugin() {
53: 		return nil
54: 	}
55: 
56: 	switch plugin.Signature {
57: 	case plugins.SignatureStatusUnsigned:
58: 		if authorized := s.authorizer.CanLoadPlugin(plugin); !authorized {
59: 			s.log.Debug("Plugin is unsigned", "pluginId", plugin.ID)
60: 			return &plugins.Error{
61: 				PluginID:        plugin.ID,
62: 				SignatureStatus: plugins.SignatureStatusUnsigned,
63: 			}
64: 		}
65: 		s.log.Warn("Permitting unsigned plugin. This is not recommended", "pluginId", plugin.ID)
66: 		return nil
67: 	case plugins.SignatureStatusInvalid:
68: 		s.log.Debug("Plugin has an invalid signature", "pluginId", plugin.ID)
69: 		return &plugins.Error{
70: 			PluginID:        plugin.ID,
71: 			SignatureStatus: plugins.SignatureStatusInvalid,
72: 		}
73: 	case plugins.SignatureStatusModified:
74: 		s.log.Debug("Plugin has a modified signature", "pluginId", plugin.ID)
75: 		return &plugins.Error{
76: 			PluginID:        plugin.ID,
77: 			SignatureStatus: plugins.SignatureStatusModified,
78: 		}
79: 	default:
80: 		s.log.Debug("Plugin has an unrecognized plugin signature state", "pluginId", plugin.ID, "signature",
81: 			plugin.Signature)
82: 		return &plugins.Error{
83: 			PluginID: plugin.ID,
84: 		}
85: 	}
86: }
